def read_local_context(base_dir: str, requested_path: str, file_map: dict[str, str]) -> str:
    # Reject absolute paths
    if requested_path.startswith('/') or (len(requested_path) > 1 and requested_path[1] == ':'):
        raise ValueError("Absolute paths are not allowed")

    # Normalize the path by resolving .. and . components
    normalized_path = normalize_path(requested_path)

    # Check if normalized path tries to escape base directory
    if normalized_path.startswith('../') or normalized_path == '..':
        raise ValueError("Path traversal outside base directory is not allowed")

    # Check if file ends with .txt
    if not normalized_path.endswith('.txt'):
        raise ValueError("Only .txt files are allowed")

    # Construct full path within base directory
    full_path = base_dir.rstrip('/') + '/' + normalized_path

    # Read from file_map
    if full_path not in file_map:
        raise ValueError(f"File not found: {requested_path}")

    return file_map[full_path]

def normalize_path(path: str) -> str:
    """Normalize a relative path by resolving . and .. components"""
    if not path:
        return ""

    # Split path into components
    components = path.split('/')
    normalized = []

    for component in components:
        if component == '' or component == '.':
            # Skip empty components and current directory references
            continue
        elif component == '..':
            # Go up one directory if possible
            if normalized:
                normalized.pop()
        else:
            # Regular directory/file name
            normalized.append(component)

    return '/'.join(normalized)

def run_bounded_sql(query: str, rows: list[dict[str, int]]) -> list[dict[str, int]]:
    def tokenize(query):
        tokens = []
        i = 0
        while i < len(query):
            if query[i].isspace():
                i += 1
            elif query[i].isalpha() or query[i] == '_':
                start = i
                while i < len(query) and (query[i].isalnum() or query[i] == '_'):
                    i += 1
                tokens.append(query[start:i])
            elif query[i].isdigit():
                start = i
                while i < len(query) and query[i].isdigit():
                    i += 1
                tokens.append(int(query[start:i]))
            elif query[i] in '=<>!':
                start = i
                if i + 1 < len(query) and query[i:i+2] in ['<=', '>=', '!=', '<>']:
                    tokens.append(query[i:i+2])
                    i += 2
                else:
                    tokens.append(query[i])
                    i += 1
            elif query[i] == '*':
                tokens.append('*')
                i += 1
            elif query[i] == ',':
                tokens.append(',')
                i += 1
            elif query[i] == ';':
                raise ValueError("Semicolons not allowed")
            else:
                i += 1
        return tokens

    def parse_query(tokens):
        if not tokens or tokens[0].upper() != 'SELECT':
            raise ValueError("Only SELECT queries allowed")

        i = 1

        # Parse columns
        if i >= len(tokens):
            raise ValueError("Invalid query")

        columns = []
        if tokens[i] == '*':
            columns = ['*']
            i += 1
        else:
            while i < len(tokens):
                if isinstance(tokens[i], str) and tokens[i].isalpha():
                    columns.append(tokens[i])
                    i += 1
                    if i < len(tokens) and tokens[i] == ',':
                        i += 1
                    else:
                        break
                else:
                    break

        if not columns:
            raise ValueError("No columns specified")

        # Parse FROM
        if i >= len(tokens) or tokens[i].upper() != 'FROM':
            raise ValueError("FROM clause required")
        i += 1

        if i >= len(tokens) or tokens[i].upper() != 'ROWS':
            raise ValueError("Only 'rows' table allowed")
        i += 1

        # Parse WHERE (optional)
        where_clause = None
        if i < len(tokens) and tokens[i].upper() == 'WHERE':
            i += 1
            if i + 2 >= len(tokens):
                raise ValueError("Invalid WHERE clause")

            column = tokens[i]
            operator = tokens[i + 1]
            value = tokens[i + 2]

            if not isinstance(column, str) or not isinstance(value, int):
                raise ValueError("Invalid WHERE clause")

            if operator not in ['=', '<', '>', '<=', '>=', '!=', '<>']:
                raise ValueError("Invalid operator")

            where_clause = (column, operator, value)
            i += 3

        # Parse LIMIT (optional)
        limit = None
        if i < len(tokens) and tokens[i].upper() == 'LIMIT':
            i += 1
            if i >= len(tokens) or not isinstance(tokens[i], int):
                raise ValueError("Invalid LIMIT clause")
            limit = tokens[i]
            i += 1

        if i < len(tokens):
            raise ValueError("Unexpected tokens at end of query")

        return columns, where_clause, limit

    def check_forbidden_keywords(tokens):
        forbidden = {'DELETE', 'UPDATE', 'INSERT', 'DROP', 'ALTER', 'CREATE', 'PRAGMA'}
        for token in tokens:
            if isinstance(token, str) and token.upper() in forbidden:
                raise ValueError(f"Forbidden keyword: {token}")

    def apply_where(rows, where_clause):
        if not where_clause:
            return rows

        column, operator, value = where_clause

        if not rows or column not in rows[0]:
            raise ValueError(f"Unknown column: {column}")

        result = []
        for row in rows:
            row_value = row[column]

            if operator == '=':
                match = row_value == value
            elif operator == '<':
                match = row_value < value
            elif operator == '>':
                match = row_value > value
            elif operator == '<=':
                match = row_value <= value
            elif operator == '>=':
                match = row_value >= value
            elif operator in ['!=', '<>']:
                match = row_value != value
            else:
                match = False

            if match:
                result.append(row)

        return result

    def select_columns(rows, columns):
        if not rows:
            return []

        if columns == ['*']:
            return rows

        # Check all columns exist
        available_columns = set(rows[0].keys())
        for col in columns:
            if col not in available_columns:
                raise ValueError(f"Unknown column: {col}")

        result = []
        for row in rows:
            new_row = {col: row[col] for col in columns}
            result.append(new_row)

        return result

    def apply_limit(rows, limit):
        if limit is None:
            return rows
        return rows[:limit]

    # Main execution
    tokens = tokenize(query)
    check_forbidden_keywords(tokens)
    columns, where_clause, limit = parse_query(tokens)

    filtered_rows = apply_where(rows, where_clause)
    selected_rows = select_columns(filtered_rows, columns)
    limited_rows = apply_limit(selected_rows, limit)

    return limited_rows

def safe_api_call(url: str, method: str, allowlist: list[str], responses: dict[str, str]) -> str:
    # Check if method is GET (case insensitive)
    if method.upper() != 'GET':
        raise ValueError("Only GET method is allowed")

    # Check if URL starts with https://
    if not url.startswith('https://'):
        raise ValueError("Only HTTPS URLs are allowed")

    # Extract host from URL
    # Remove https:// prefix
    url_without_scheme = url[8:]  # Remove 'https://'

    # Find the host part (everything before first '/' or end of string)
    slash_index = url_without_scheme.find('/')
    if slash_index == -1:
        host = url_without_scheme
    else:
        host = url_without_scheme[:slash_index]

    # Remove port if present
    colon_index = host.find(':')
    if colon_index != -1:
        host = host[:colon_index]

    # Check if host is in allowlist
    if host not in allowlist:
        raise ValueError("Host not in allowlist")

    # Check if host is localhost or private IP
    if _is_forbidden_host(host):
        raise ValueError("Localhost and private IPs are not allowed")

    # Look up response
    response_key = f"{method.upper()} {url}"
    if response_key not in responses:
        raise ValueError("Response not found")

    return responses[response_key]

def _is_forbidden_host(host: str) -> bool:
    # Check for localhost
    if host.lower() in ['localhost', '127.0.0.1', '::1']:
        return True

    # Check if it's an IP address
    if _is_ip_address(host):
        return _is_private_ip(host)

    return False

def _is_ip_address(host: str) -> bool:
    # Simple check for IPv4
    parts = host.split('.')
    if len(parts) == 4:
        try:
            for part in parts:
                num = int(part)
                if num < 0 or num > 255:
                    return False
            return True
        except ValueError:
            return False

    # Simple check for IPv6 (contains colons)
    if ':' in host:
        return True

    return False

def _is_private_ip(ip: str) -> bool:
    # Check for IPv4 private ranges
    if '.' in ip:
        parts = ip.split('.')
        if len(parts) == 4:
            try:
                first = int(parts[0])
                second = int(parts[1])

                # 10.0.0.0/8
                if first == 10:
                    return True

                # 172.16.0.0/12
                if first == 172 and 16 <= second <= 31:
                    return True

                # 192.168.0.0/16
                if first == 192 and second == 168:
                    return True

                # 127.0.0.0/8 (localhost)
                if first == 127:
                    return True

            except ValueError:
                pass

    # For IPv6, consider all as private for safety (since we can't import ipaddress)
    if ':' in ip:
        return True

    return False

def bounded_evaluate(expression: str, variables: dict[str, int], max_nodes: int = 32) -> int:
    def parse_expression(expr):
        # Simple recursive descent parser
        tokens = tokenize(expr)
        pos = [0]  # Use list to allow modification in nested functions

        def peek():
            return tokens[pos[0]] if pos[0] < len(tokens) else None

        def consume():
            token = tokens[pos[0]] if pos[0] < len(tokens) else None
            pos[0] += 1
            return token

        def parse_expr():
            left = parse_term()
            while peek() in ['+', '-']:
                op = consume()
                right = parse_term()
                left = ('binop', op, left, right)
            return left

        def parse_term():
            left = parse_factor()
            while peek() in ['*', '//']:
                op = consume()
                right = parse_factor()
                left = ('binop', op, left, right)
            return left

        def parse_factor():
            token = peek()
            if token == '-':
                consume()
                operand = parse_factor()
                return ('unary', '-', operand)
            elif token == '(':
                consume()
                expr = parse_expr()
                if consume() != ')':
                    raise ValueError("Missing closing parenthesis")
                return expr
            elif token and (token.isdigit() or (token.startswith('-') and token[1:].isdigit())):
                return ('num', int(consume()))
            elif token and token.isidentifier():
                return ('var', consume())
            else:
                raise ValueError(f"Unexpected token: {token}")

        return parse_expr()

    def tokenize(expr):
        tokens = []
        i = 0
        while i < len(expr):
            if expr[i].isspace():
                i += 1
            elif expr[i] in '+-*()':
                tokens.append(expr[i])
                i += 1
            elif expr[i:i+2] == '//':
                tokens.append('//')
                i += 2
            elif expr[i].isdigit():
                j = i
                while j < len(expr) and expr[j].isdigit():
                    j += 1
                tokens.append(expr[i:j])
                i = j
            elif expr[i].isalpha() or expr[i] == '_':
                j = i
                while j < len(expr) and (expr[j].isalnum() or expr[j] == '_'):
                    j += 1
                tokens.append(expr[i:j])
                i = j
            else:
                raise ValueError(f"Invalid character: {expr[i]}")
        return tokens

    def count_nodes(ast):
        if ast[0] == 'num':
            return 1
        elif ast[0] == 'var':
            return 1
        elif ast[0] == 'unary':
            return 1 + count_nodes(ast[2])
        elif ast[0] == 'binop':
            return 1 + count_nodes(ast[2]) + count_nodes(ast[3])
        else:
            raise ValueError(f"Unknown AST node type: {ast[0]}")

    def evaluate_ast(ast):
        if ast[0] == 'num':
            return ast[1]
        elif ast[0] == 'var':
            var_name = ast[1]
            if var_name not in variables:
                raise ValueError(f"Unknown variable: {var_name}")
            return variables[var_name]
        elif ast[0] == 'unary':
            op, operand = ast[1], ast[2]
            if op == '-':
                return -evaluate_ast(operand)
            else:
                raise ValueError(f"Unknown unary operator: {op}")
        elif ast[0] == 'binop':
            op, left, right = ast[1], ast[2], ast[3]
            left_val = evaluate_ast(left)
            right_val = evaluate_ast(right)
            if op == '+':
                return left_val + right_val
            elif op == '-':
                return left_val - right_val
            elif op == '*':
                return left_val * right_val
            elif op == '//':
                if right_val == 0:
                    raise ValueError("Division by zero")
                return left_val // right_val
            else:
                raise ValueError(f"Unknown binary operator: {op}")
        else:
            raise ValueError(f"Unknown AST node type: {ast[0]}")

    # Parse the expression
    ast = parse_expression(expression)

    # Check node count
    if count_nodes(ast) > max_nodes:
        raise ValueError(f"Expression has too many nodes (>{max_nodes})")

    # Evaluate and return result
    return evaluate_ast(ast)
